import * as THREE from 'three';
import { OBJExporter } from 'three/examples/jsm/exporters/OBJExporter.js';
import { createScene } from './data/object.js';
import fs from 'fs';
import path from 'path';

const root = createScene();
root.updateMatrixWorld(true);

const exporter = new OBJExporter();

const outputDir = '/root/output';
const partMeshesDir = path.join(outputDir, 'part_meshes');
const linksDir = path.join(outputDir, 'links');

fs.mkdirSync(partMeshesDir, { recursive: true });
fs.mkdirSync(linksDir, { recursive: true });

// Helper: export a single mesh to OBJ with world-space vertices
function exportMeshToOBJ(mesh) {
    // Clone the mesh so we can bake world transform without affecting original
    const cloned = mesh.clone();
    cloned.geometry = mesh.geometry.clone();

    // Apply the mesh's world matrix to the geometry
    cloned.geometry.applyMatrix4(mesh.matrixWorld);

    // Reset the clone's transform so OBJExporter doesn't double-apply
    cloned.position.set(0, 0, 0);
    cloned.rotation.set(0, 0, 0);
    cloned.scale.set(1, 1, 1);
    cloned.updateMatrixWorld(true);

    // Create a temporary scene with just this mesh
    const scene = new THREE.Scene();
    scene.add(cloned);

    return exporter.parse(scene);
}

// Helper: export a group of meshes as a single combined OBJ
function exportGroupToOBJ(group) {
    const scene = new THREE.Scene();

    // Collect all meshes in the group (recursively)
    group.traverse((child) => {
        if (child.isMesh) {
            const cloned = child.clone();
            cloned.geometry = child.geometry.clone();
            cloned.geometry.applyMatrix4(child.matrixWorld);
            cloned.position.set(0, 0, 0);
            cloned.rotation.set(0, 0, 0);
            cloned.scale.set(1, 1, 1);
            cloned.updateMatrixWorld(true);
            scene.add(cloned);
        }
    });

    return exporter.parse(scene);
}

// Process each top-level part (direct children of root that are Groups)
