# OBJ Export from Three.js

## Overview
How to export Three.js meshes to OBJ format using the built-in OBJExporter.

## Setup
"'```javascript
import { OBJExporter } from '"'three/examples/jsm/exporters/OBJExporter.js';
const exporter = new OBJExporter();
"'```

## Export a Single Mesh (World Space)
```javascript
function exportMeshToOBJ(mesh) {
    const cloned = mesh.clone();
    cloned.geometry = mesh.geometry.clone();
    cloned.geometry.applyMatrix4(mesh.matrixWorld);
    cloned.position.set(0, 0, 0);
    cloned.rotation.set(0, 0, 0);
    cloned.scale.set(1, 1, 1);
    cloned.updateMatrixWorld(true);
    const scene = new THREE.Scene();
    scene.add(cloned);
    return exporter.parse(scene);
}
```

## Export a Group as Combined OBJ
```javascript
function exportGroupToOBJ(group) {
    const scene = new THREE.Scene();
    group.traverse(child => {
        if (child.isMesh) {
            const cloned = child.clone();
            cloned.geometry = child.geometry.clone();
            cloned.geometry.applyMatrix4(child.matrixWorld);
            cloned.position.set(0, 0, 0);
            cloned.rotation.set(0, 0, 0);
            cloned.scale.set(1, 1, 1);
            scene.add(cloned);
        }
    });
    return exporter.parse(scene);
}
```

## OBJ Format Basics
- `v x y z` — vertex position
- `vn x y z` — vertex normal
- `f v1 v2 v3` — face (1-indexed vertex references)
- `o name` — object name
EOF
