import * as THREE from 'three';
import { OBJExporter } from 'three/examples/jsm/exporters/OBJExporter.js';
import { createScene } from './data/object.js';
import fs from 'fs';
import path from 'path';

// Create the scene and update world matrices
const root = createScene();
const scene = new THREE.Scene();
scene.add(root);
scene.updateMatrixWorld(true);

// Collect part groups (direct children of root that are Groups)
// and any direct meshes of root as individual parts
const parts = new Map(); // partName -> [meshes]

function collectMeshes(group, partName) {
    const meshes = [];
    group.traverse((child) => {
        if (child.isMesh) {
            meshes.push(child);
        }
    });
    return meshes;
}

// The root is 'ferris_wheel' group. Its direct children are the \"parts\":
// support_structure and wheel_structure
for (const child of root.children) {
    if (child.isGroup) {
        const partName = child.name;
        const meshes = collectMeshes(child, partName);
        parts.set(partName, meshes);
    } else if (child.isMesh) {
        // Direct mesh child of root - treat as its own part
        const partName = child.name;
        parts.set(partName, [child]);
    }
}

console.log(\"Parts found:\");
for (const [name, meshes] of parts) {
    console.log("'`  ${name}: ${meshes.length} meshes`);
    for (const m of meshes.slice(0, 5)) {
        console.log(`    - ${m.name}`);
    }
    if (meshes.length > 5) console.log(`    ... and ${meshes.length - 5} more`);
}

// Helper: write OBJ from a geometry (already in world space)
function geometryToOBJ(geometry) {
    const pos = geometry.getAttribute('"'position');
    const idx = geometry.getIndex();
    let obj = '';

    // Write vertices
    for (let i = 0; i < pos.count; i++) {
        obj += "'`v ${pos.getX(i)} ${pos.getY(i)} ${pos.getZ(i)}'"\\n"'`;
    }

    // Write faces
    if (idx) {
        for (let i = 0; i < idx.count; i += 3) {
            obj += `f ${idx.getX(i) + 1} ${idx.getX(i + 1) + 1} ${idx.getX(i + 2) + 1}'"\\n"'`;
        }
    } else {
        // Non-indexed geometry
        for (let i = 0; i < pos.count; i += 3) {
            obj += `f ${i + 1} ${i + 2} ${i + 3}'"\\n"'`;
        }
    }

    return obj;
}

// Helper: get world-space geometry for a mesh
function getWorldGeometry(mesh) {
    const geo = mesh.geometry.clone();
    geo.applyMatrix4(mesh.matrixWorld);
    return geo;
}

// Helper: merge multiple geometries
function mergeGeometries(geometries) {
    let totalVerts = 0;
    let totalIndices = 0;

    for (const geo of geometries) {
        totalVerts += geo.getAttribute('"'position').count;
        const idx = geo.getIndex();
        if (idx) totalIndices += idx.count;
        else totalIndices += geo.getAttribute('position').count;
    }

    const positions = new Float32Array(totalVerts * 3);
    const indices = [];
    let vertOffset = 0;
    let posOffset = 0;

    for (const geo of geometries) {
        const pos = geo.getAttribute('position');
        for (let i = 0; i < pos.count; i++) {
            positions[posOffset++] = pos.getX(i);
            positions[posOffset++] = pos.getY(i);
            positions[posOffset++] = pos.getZ(i);
        }

        const idx = geo.getIndex();
        if (idx) {
            for (let i = 0; i < idx.count; i++) {
                indices.push(idx.getX(i) + vertOffset);
            }
        } else {
            for (let i = 0; i < pos.count; i++) {
                indices.push(i + vertOffset);
            }
        }

        vertOffset += pos.count;
    }

    const merged = new THREE.BufferGeometry();
    merged.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    merged.setIndex(indices);
    return merged;
}

// Create output directories
const outputDir = '/root/output';
const partMeshesDir = path.join(outputDir, 'part_meshes');
const linksDir = path.join(outputDir, 'links');

fs.mkdirSync(partMeshesDir, { recursive: true });
fs.mkdirSync(linksDir, { recursive: true });

// Export each part
for (const [partName, meshes] of parts) {
    // Create part directory
    const partDir = path.join(partMeshesDir, partName);
    fs.mkdirSync(partDir, { recursive: true });

    const worldGeometries = [];

    for (const mesh of meshes) {
        const worldGeo = getWorldGeometry(mesh);
        worldGeometries.push(worldGeo);

        // Write individual mesh OBJ
        const objContent = geometryToOBJ(worldGeo);
        const meshFile = path.join(partDir, "'`${mesh.name}.obj`);
        fs.writeFileSync(meshFile, objContent);
    }

    // Write combined link OBJ
    const mergedGeo = mergeGeometries(worldGeometries);
    const linkContent = geometryToOBJ(mergedGeo);
    const linkFile = path.join(linksDir, `${partName}.obj`);
    fs.writeFileSync(linkFile, linkContent);

    console.log(`Exported ${partName}: ${meshes.length} meshes, link written`);
}

console.log("'"\\nDone"'! Output written to /root/output/");
