        const cabinBodyGeometry = new THREE.CylinderGeometry(cabinRadius, cabinRadius, cabinHeight, 8); // Octagonal cabin
        const cabinBodyMesh = new THREE.Mesh(cabinBodyGeometry);
        cabinBodyMesh.name = `cabin_body_${i}`;
