    // OBJExporter.parse() traverses the object and exports all meshes it finds
    // For a single mesh, it will export just that mesh in world space
    return exporter.parse(mesh);
}

// Helper: export a group (all its descendant meshes) to OBJ
function exportGroupToOBJ(group) {
    return exporter.parse(group);
}

