\"\"\"Self-test: verify internal consistency of the export.\"\"\"
import os
from pathlib import Path
import numpy as np

OUTPUT_DIR = \"/root/output\"

def parse_obj_vertices(filepath):
    vertices = []
    with open(filepath, \"r\") as f:
        for line in f:
            if line.startswith(\"v \"):
                parts = line.strip().split()
                if len(parts) >= 4:
                    vertices.append([float(parts[1]), float(parts[2]), float(parts[3])])
    return np.array(vertices, dtype=np.float32)

def test_structure():
    part_meshes = Path(OUTPUT_DIR) / \"part_meshes\"
    links = Path(OUTPUT_DIR) / \"links\"

    assert part_meshes.exists(), \"Missing part_meshes\"
    assert links.exists(), \"Missing links\"

    part_dirs = sorted([p for p in part_meshes.iterdir() if p.is_dir()])
    link_files = sorted(links.glob(\"*.obj\"))

    print(f\"Part directories: {len(part_dirs)}\")
    print(f\"Link files: {len(link_files)}\")

    # Check that each part dir has a corresponding link file
    part_names = {p.name for p in part_dirs}
    link_names = {p.stem for p in link_files}
    assert part_names == link_names, f\"Mismatch: parts={part_names - link_names}, links={link_names - part_names}\"

    # For each part, verify link = concatenation of part meshes
    for part_dir in part_dirs:
        mesh_files = sorted(part_dir.glob(\"*.obj\"))
        link_file = links / f\"{part_dir.name}.obj\"

        # Concatenate all mesh vertices
        all_mesh_verts = []
        for mf in mesh_files:
            verts = parse_obj_vertices(mf)
            if len(verts) > 0:
                all_mesh_verts.append(verts)

        if all_mesh_verts:
            concat_verts = np.concatenate(all_mesh_verts, axis=0)
        else:
            concat_verts = np.array([], dtype=np.float32)

        link_verts = parse_obj_vertices(link_file)

        assert len(concat_verts) == len(link_verts), \\
            f\"{part_dir.name}: mesh verts={len(concat_verts)}, link verts={len(link_verts)}\"

        # Check vertices match exactly
        if len(concat_verts) > 0:
            diff = np.abs(concat_verts - link_verts).max()
            assert diff < 1e-6, f\"{part_dir.name}: max vertex diff={diff}\"

        print(f\"  {part_dir.name}: {len(mesh_files)} meshes, {len(link_verts)} vertices ✓\")

if __name__ == \"__main__\":
    test_structure()
    print(\"\\nAll self-tests passed"'!")
