import * as THREE from 'three';
import { OBJExporter } from 'three/examples/jsm/exporters/OBJExporter.js';
import { createScene } from './data/object.js';
import fs from 'fs';
import path from 'path';

const root = createScene();
root.updateMatrixWorld(true);

const exporter = new OBJExporter();

const partMeshesDir = '/root/output/part_meshes';
const linksDir = '/root/output/links';

// Clean and create output dirs
fs.rmSync('/root/output', { recursive: true, force: true });
fs.mkdirSync(partMeshesDir, { recursive: true });
fs.mkdirSync(linksDir, { recursive: true });

// Find all part groups (direct children of root that are Groups)
// and also handle direct mesh children of root
for (const child of root.children) {
    if (child.isGroup) {
        const partName = child.name;
        const partDir = path.join(partMeshesDir, partName);
        fs.mkdirSync(partDir, { recursive: true });

        // Export each mesh child individually for part_meshes
        for (const mesh of child.children) {
            if (mesh.isMesh) {
                // Export single mesh using OBJExporter
                const objStr = exporter.parse(mesh);
                fs.writeFileSync(path.join(partDir, "'`${mesh.name}.obj`), objStr);
            } else if (mesh.isGroup) {
                // Nested group (like cabin groups inside wheel_structure)
                const subPartName = mesh.name;
                const subPartDir = path.join(partMeshesDir, subPartName);
                fs.mkdirSync(subPartDir, { recursive: true });

                for (const subMesh of mesh.children) {
                    if (subMesh.isMesh) {
                        const objStr = exporter.parse(subMesh);
                        fs.writeFileSync(path.join(subPartDir, `${subMesh.name}.obj`), objStr);
                    }
                }

                // Export the whole sub-group as a link
                const linkObjStr = exporter.parse(mesh);
                fs.writeFileSync(path.join(linksDir, `${subPartName}.obj`), linkObjStr);
            }
        }

        // Export the whole group as a link
        const linkObjStr = exporter.parse(child);
        fs.writeFileSync(path.join(linksDir, `${partName}.obj`), linkObjStr);
    }
}

// List what was created
console.log('"'=== Part meshes ===');
for (const dir of fs.readdirSync(partMeshesDir).sort()) {
    const files = fs.readdirSync(path.join(partMeshesDir, dir)).sort();
    console.log("'`  ${dir}/: ${files.length} files`);
}
console.log('"'=== Links ===');
for (const f of fs.readdirSync(linksDir).sort()) {
    console.log("'`  ${f}`);
}
