    const legBL = createCylinderBeam(backLeftFoot, backAxlePoint, supportLegRadius, 'support_leg_back_left');
    const legBR = createCylinderBeam(backRightFoot, backAxlePoint, supportLegRadius, 'support_leg_back_right');
