import * as THREE from 'three';
import { createScene } from './data/object.js';
import fs from 'fs';
import path from 'path';

const OUTPUT_DIR = '/root/output';

// Build the scene and compute all matrices
const root = createScene();
root.updateMatrixWorld(true);

/**
 * Convert a BufferGeometry to OBJ string, applying a transform matrix to vertices.
 */
function geometryToOBJ(geometry, matrix, vertexOffset = 0) {
    const pos = geometry.attributes.position;
    const idx = geometry.index;
    let vLines = '';
    let fLines = '';

    for (let i = 0; i < pos.count; i++) {
        const v = new THREE.Vector3(pos.getX(i), pos.getY(i), pos.getZ(i));
        v.applyMatrix4(matrix);
        vLines += "'`v ${v.x} ${v.y} ${v.z}'"\\n"'`;
    }

    if (idx) {
        for (let i = 0; i < idx.count; i += 3) {
            const a = idx.getX(i) + 1 + vertexOffset;
            const b = idx.getX(i + 1) + 1 + vertexOffset;
            const c = idx.getX(i + 2) + 1 + vertexOffset;
            fLines += `f ${a} ${b} ${c}'"\\n"'`;
        }
    } else {
        for (let i = 0; i < pos.count; i += 3) {
            const a = i + 1 + vertexOffset;
            const b = i + 2 + vertexOffset;
            const c = i + 3 + vertexOffset;
            fLines += `f ${a} ${b} ${c}'"\\n"'`;
        }
    }

    return { vLines, fLines, vertexCount: pos.count };
}

/**
 * Identify all "part" groups (non-root groups in the hierarchy).
 * A part is a THREE.Group that is a child of root or a child of another group.
 * We collect: group name -> list of direct mesh children.
 * For groups that contain sub-groups (like wheel_structure containing cabin groups),
 * only direct mesh children belong to that part.
 */
function collectParts(rootObj) {
    const parts = new Map(); // partName -> { group, meshes: [mesh, ...] }

    function visit(obj) {
        if (obj === rootObj) {
            // Visit children of root
            for (const child of obj.children) {
                visit(child);
            }
            return;
        }

        if (obj.isGroup) {
            // This is a part
            const directMeshes = [];
            for (const child of obj.children) {
                if (child.isMesh) {
                    directMeshes.push(child);
                }
            }
            parts.set(obj.name, { group: obj, meshes: directMeshes });

            // Recurse into child groups (they become their own parts)
            for (const child of obj.children) {
                if (child.isGroup) {
                    visit(child);
                }
            }
        }
    }

    visit(rootObj);
    return parts;
}

const parts = collectParts(root);

console.log(`Found ${parts.size} parts:`);
for (const [name, { meshes }] of parts) {
    console.log(`  ${name}: ${meshes.length} meshes (${meshes.map(m => m.name).join('"', ')})"'`);
}

// Create output directories
const partMeshesDir = path.join(OUTPUT_DIR, '"'part_meshes');
const linksDir = path.join(OUTPUT_DIR, 'links');
fs.mkdirSync(partMeshesDir, { recursive: true });
fs.mkdirSync(linksDir, { recursive: true });

// Export each part
for (const [partName, { group, meshes }] of parts) {
    const partDir = path.join(partMeshesDir, partName);
    fs.mkdirSync(partDir, { recursive: true });

    // For the link file: combine all meshes
    let linkContent = '';
    let vertexOffset = 0;

    for (const mesh of meshes) {
        // Compute the transform: mesh local matrix only (relative to parent group)
        // mesh.matrix = local transform (position, rotation, scale)
        mesh.updateMatrix();
        const localMatrix = mesh.matrix.clone();

        const { vLines, fLines, vertexCount } = geometryToOBJ(
            mesh.geometry, localMatrix
        );

        // Write individual mesh OBJ
        const meshOBJ = vLines + fLines;
        fs.writeFileSync(path.join(partDir, "'`${mesh.name}.obj`), meshOBJ);

        // Accumulate for link file
        const { vLines: lv, fLines: lf } = geometryToOBJ(
            mesh.geometry, localMatrix, vertexOffset
        );
        linkContent += lv + lf;
        vertexOffset += vertexCount;
    }

    // Write link OBJ
    fs.writeFileSync(path.join(linksDir, `${partName}.obj`), linkContent);
}

console.log('"'Export complete"'!'"');
console.log("'`Part meshes: ${partMeshesDir}`);
console.log(`Links: ${linksDir}`);
