import path from 'path';

const OUTPUT_DIR = '/root/output';
const exporter = new OBJExporter();

// Build the scene and compute all matrices
const root = createScene();
root.updateMatrixWorld(true);

/**
 * Collect parts: each THREE.Group (non-root) is a part.
 * A part's meshes are its direct Mesh children only.
 */
function collectParts(rootObj) {
    const parts = new Map();
    function visit(obj) {
        if (obj === rootObj) {
            for (const child of obj.children) visit(child);
            return;
        }
        if (obj.isGroup) {
            const directMeshes = obj.children.filter(c => c.isMesh);
            parts.set(obj.name, { group: obj, meshes: directMeshes });
            for (const child of obj.children) {
                if (child.isGroup) visit(child);
            }
        }
    }
    visit(rootObj);
    return parts;
}

const parts = collectParts(root);

