fs.mkdirSync(linksDir, { recursive: true });

// Use OBJExporter on individual meshes (world space)
for (const [partName, { group, meshes }] of parts) {
    const partDir = path.join(partMeshesDir, partName);
    fs.mkdirSync(partDir, { recursive: true });

    for (const mesh of meshes) {
        const objStr = exporter.parse(mesh);
        fs.writeFileSync(path.join(partDir, "'`${mesh.name}.obj`), objStr);
